                      </div>
                    )}
                    {cd.improved_response && (
                      <div className="p-3 rounded-lg bg-purple-50 border border-purple-100">
                        <h5 className="text-xs font-semibold text-purple-800 mb-1.5">⭐ Example Strong Response</h5>
